INSERT INTO product_reviews (review_id, product_id, reviewer_name, rating, review_text, created_at) VALUES
(1, 1, 'CatLover42', 5, 'My cat absolutely loves this feeder! The AI scheduling is incredibly accurate and my cat has never been healthier.', '2026-01-15 10:30:00'),
(2, 1, 'WhiskersMom', 4, 'Great feeder overall. The nap cycle detection is spot on, but the app could use some UI improvements.', '2026-02-01 14:22:00'),
(3, 1, 'FelineFanatic', 3, 'Decent product but took a while to calibrate to my cat''s schedule. Works well once set up.', '2026-02-20 09:15:00'),
(4, 2, 'TidyCatDad', 5, 'Best litter box I''ve ever owned. The self-cleaning feature is a game changer. Worth every penny!', '2026-01-10 16:45:00'),
(5, 2, 'PurrfectHome', 4, 'Very quiet operation and the health reports are surprisingly detailed. Highly recommend.', '2026-03-05 11:00:00'),
(6, 3, 'LaserChaser99', 5, 'My cats are OBSESSED with CatFlix. The bird-watching streams keep them entertained for hours.', '2026-01-22 20:30:00'),
(7, 4, 'OutdoorKitty', 4, 'The GPS tracking is excellent and the mood detection is surprisingly accurate. Battery life could be better.', '2026-02-14 08:00:00'),
(8, 4, 'ZoomieCat', 5, 'Love the zoomie alerts! Finally I can track my cat''s activity patterns. The tail position analysis is hilarious and useful.', '2026-03-01 17:30:00'),
(9, 5, 'NightOwlCat', 5, 'Night vision is crystal clear. Caught my cat opening the fridge at 3am. Worth it just for that!', '2026-01-28 23:15:00'),
(10, 5, 'RemoteWorker', 3, 'Camera quality is good but the treat dispensing mechanism jams occasionally. Customer support was helpful though.', '2026-02-10 13:45:00'),
(11, 7, 'ModernCatLady', 5, 'This cat tree is a work of art. My cats love the charging stations and the speakers play calming music.', '2026-03-10 19:00:00'),
(12, 9, 'SpaDayCat', 4, 'The grooming bot is gentle and my cat actually enjoys it. Stress level detection works well.', '2026-02-25 15:30:00');
